<template>
  <div class="psd-file">
    <el-row :gutter="10" class="main-content-row">
      <el-col :span="6" class="sidebar-col">
        <!-- 左侧分类导航 -->
        <div class="sidebar">
          <el-menu
            :default-active="String(currentCategory)"
            background-color="#252525"
            text-color="#fff"
            active-text-color="#ffd04b"
            @select="handleSelect"
          >
            <template v-for="item in categoryList">
              <el-menu-item
                :key="String(item.id)"
                :index="String(item.id)"
                :class="{
                  'menu-item-active': String(item.id) === currentCategory
                }"
              >
                <template slot="title">
                  <span>{{ item.nameCn }}</span>
                </template>
              </el-menu-item>
            </template>
          </el-menu>
        </div>
      </el-col>

      <!-- 右侧素材展示区 -->
      <el-col :span="18" class="content-col">
        <div class="content" :infinite-scroll-distance="10" :infinite-scroll-immediate="false" v-infinite-scroll="loadList">
          <div v-for="(item, index) in materialAllList" :key="index" @click="handleBaiduPath(item)" class="psd-item">
            <el-image fit="fill" :src="item.thumbnail" class="psd-image"> </el-image>
            <div class="psd-tag psd-left-top">点击图片获取</div>
            <div class="psd-tag psd-right-bottom" v-if="item.params && item.params.isBuy">
              <span>已购买</span>
            </div>
            <div class="psd-tag psd-right-bottom" v-else>
              <span v-if="item.discountAmount === 0"
                ><p>{{ item.normalAmount }}</p>
                币</span
              >
              <span v-else
                >限时
                <p>{{ item.discountAmount }}</p>
                币</span
              >
            </div>
          </div>
        </div>
      </el-col>
    </el-row>

    <!--    PSD素材购买弹窗-->
    <el-dialog :visible.sync="psdDialogVisible" append-to-body center class="recharge-dialog" width="90%">
      <el-form :model="psdDialogForm">
        <el-form-item style="margin-bottom: 0">
          <el-image :src="psdDialogForm.thumbnail" fit="fill" style="width: 100%; height: 160px; border-radius: 20px" />
        </el-form-item>
      </el-form>
      <span class="dialog-footer" slot="footer">
        <el-button type="text">账户余额：{{ userInfo.coin ? userInfo.coin : 0 }}币</el-button>
        <el-button type="text" v-if="psdDialogForm.discountAmount">限时特惠：{{ psdDialogForm.discountAmount }}币</el-button>
        <el-button type="text" v-else>购买鼠币：{{ psdDialogForm.normalAmount }}币</el-button>
      </span>
      <span class="dialog-footer" slot="footer">
        <el-button @click="handleRecharge" size="mini" type="primary">充值土拨鼠货币</el-button>
        <el-button @click="handleBuyPsd(psdDialogForm)" size="mini" type="primary">确认购买</el-button>
      </span>
    </el-dialog>

    <!--    PSD素材购买成功链接-->
    <el-dialog
      :visible.sync="psdBaiduLinkDialogVisible"
      append-to-body
      class="recharge-dialog"
      size="small"
      width="95%"
      :before-close="psdFileBaiduLink"
    >
      <el-form :model="psdBaiduLinkForm" label-position="top" label-suffix="复制链接" style="height: 300px">
        <el-form-item>
          <template v-slot:label>
            <span style="color: white">复制以下百度网盘链接到浏览器打开</span>
          </template>
          <el-input
            @focus="handleCopy(psdBaiduLinkForm.highDefinition)"
            placeholder="请输入内容"
            class="link-input"
            v-model="psdBaiduLinkForm.highDefinition"
          >
            <template v-slot:suffix>
              <span @click="handleCopy(psdBaiduLinkForm.highDefinition)" class="copy-btn">复制链接</span>
            </template>
          </el-input>
        </el-form-item>
        <el-form-item v-if="psdBaiduLinkForm.extractCode">
          <template v-slot:label>
            <span style="color: white">百度网盘提取密码</span>
          </template>
          <el-input
            @focus="handleCopy(psdBaiduLinkForm.extractCode)"
            placeholder="请输入内容"
            class="link-input"
            v-model="psdBaiduLinkForm.extractCode"
          >
            <template v-slot:suffix>
              <span @click="handleCopy(psdBaiduLinkForm.extractCode)" class="copy-btn">复制密码</span>
            </template>
          </el-input>
        </el-form-item>
      </el-form>
    </el-dialog>
  </div>
</template>

<script>
import { getCategoryList, getProductList, getMemUserInfo } from '@/api/main';
import { addConsumeRecord } from '@/api/psdFile';
import { copyText } from '@/utils/common';

export default {
  name: 'AddMaterial',
  props: {
    categoryParentId: {
      type: String,
      default: '9'
    }
  },
  data() {
    return {
      totalCount: 0,
      materialList: [],
      materialAllList: [],
      categoryList: [],
      currentCategory: '-1', // 默认选中收藏
      psdDialogVisible: false,
      psdDialogForm: {},
      psdBaiduLinkDialogVisible: false,
      psdBaiduLinkForm: {},
      queryParams: {
        firstCategoryId: null,
        categoryId: null,
        thirdCategoryId: null,
        fourCategoryId: null,
        pageNum: 1,
        pageSize: 20
      },
      userInfo: {}
    };
  },
  created() {
    this.getCategories();
  },
  methods: {
    async getCategories() {
      try {
        const params = { parentId: this.categoryParentId };
        const response = await getCategoryList(params);
        this.categoryList = response.data || [];
        if (this.categoryList.length > 0) {
          await this.handleSelect(String(this.categoryList[0].id), null);
        }
      } catch (error) {
        console.error('获取分类列表失败:', error);
      }
    },
    async getMaterials() {
      try {
        const response = await getProductList(this.queryParams);
        this.totalCount = response.data && response.data.total ? response.data.total : 0;
        this.materialList = response.data && response.data.records ? response.data.records : [];
      } catch (error) {
        console.error('获取素材列表失败:', error);
        this.materialList = [];
      }
    },
    async handleSelect(key, keyPath) {
      this.currentCategory = key;
      this.queryParams.pageNum = 1;
      this.queryParams.categoryId = key;
      await this.getMaterials();
      this.materialAllList = this.materialList;
    },
    async loadList() {
      if (this.materialAllList.length >= this.totalCount) {
        return; // 没有更多数据了
      }
      this.queryParams.pageNum += 1;
      await this.getMaterials();
      this.materialAllList = this.materialAllList.concat(this.materialList);
    },
    async handleBaiduPath(item) {
      if (item.params && item.params.isBuy) {
        this.showPsdBaiduLink(item);
      } else {
        this.getUserInfo();
        this.psdDialogVisible = true;
        this.psdDialogForm = item;
      }
    },
    getUserInfo() {
      // 获取用户信息
      getMemUserInfo().then((response) => {
        this.userInfo = response.data;
      });
    },
    handleBuyPsd(item) {
      let coinTemp = this.userInfo.coin ? this.userInfo.coin : 0;
      let buyAmount = item.discountAmount ? item.discountAmount : item.normalAmount;
      if (coinTemp < buyAmount) {
        this.$message.error('余额不足，请先充值');
      } else {
        let params = {
          productId: item.id
        };
        addConsumeRecord(params).then((res) => {
          if (res.code === 200) {
            this.$message.success('购买成功');
            this.psdDialogVisible = false;
            this.$set(item, 'params', { ...item.params, isBuy: true });
            this.showPsdBaiduLink(item);
          } else if (res.code === 1002) {
            this.$message.error('余额不足，请先充值');
          } else {
            this.$message.error(res.message);
          }
        });
      }
    },
    showPsdBaiduLink(item) {
      this.psdBaiduLinkDialogVisible = true;
      this.psdBaiduLinkForm = item;
    },
    psdFileBaiduLink(done) {
      this.psdBaiduLinkDialogVisible = false;
      this.$emit('refreshUserInfo', null); // 通知父组件刷新用户信息
      done && done();
    },
    handleCopy(text) {
      const status = copyText(text);
      if (status) {
        this.$message.success('复制成功');
      } else {
        this.$message.error('复制失败');
      }
    },
    handleRecharge() {
      this.$emit('handleRecharge', null); // 通知父组件刷新用户信息
    },
    refreshPsdFile() {
      if (!this.psdDialogVisible) {
        return;
      }
      this.getUserInfo();
    }
  }
};
</script>

